import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";

const SHOPIFY_STORE = process.env.SHOPIFY_STORE; // e.g. "your-store.myshopify.com"
const SHOPIFY_ACCESS_TOKEN = process.env.SHOPIFY_ACCESS_TOKEN;
const API_VERSION = "2025-01";

async function shopifyGraphQL(query, variables = {}) {
  const url = `https://${SHOPIFY_STORE}/admin/api/${API_VERSION}/graphql.json`;
  const res = await fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-Shopify-Access-Token": SHOPIFY_ACCESS_TOKEN,
    },
    body: JSON.stringify({ query, variables }),
  });

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Shopify API Error (${res.status}): ${text}`);
  }

  return res.json();
}

async function runShopifyQL(shopifyqlQuery) {
  const gql = `
    query ($query: String!) {
      shopifyqlQuery(query: $query) {
        __typename
        ... on TableResponse {
          tableData {
            unformattedData
            rowData
            columns {
              name
              dataType
              displayName
            }
          }
        }
        ... on PolarisVizResponse {
          data {
            key
            data {
              key
              value
            }
          }
        }
        parseErrors {
          code
          message
          range {
            start { line character }
            end { line character }
          }
        }
      }
    }
  `;

  const result = await shopifyGraphQL(gql, { query: shopifyqlQuery });

  if (result.errors) {
    throw new Error(`GraphQL errors: ${JSON.stringify(result.errors)}`);
  }

  const response = result.data.shopifyqlQuery;

  if (response.parseErrors && response.parseErrors.length > 0) {
    throw new Error(`ShopifyQL parse errors: ${JSON.stringify(response.parseErrors)}`);
  }

  return response;
}

function formatTableResponse(response) {
  if (response.__typename === "TableResponse" && response.tableData) {
    const { columns, rowData } = response.tableData;
    const headers = columns.map((c) => c.displayName || c.name);

    let result = `| ${headers.join(" | ")} |\n`;
    result += `| ${headers.map(() => "---").join(" | ")} |\n`;

    for (const row of rowData) {
      result += `| ${row.join(" | ")} |\n`;
    }

    result += `\n合計行数: ${rowData.length}`;
    return result;
  }

  if (response.__typename === "PolarisVizResponse" && response.data) {
    let result = "";
    for (const series of response.data) {
      result += `### ${series.key}\n`;
      for (const point of series.data) {
        result += `- ${point.key}: ${point.value}\n`;
      }
      result += "\n";
    }
    return result;
  }

  return "データがありません。";
}

const server = new Server(
  { name: "shopify-mcp-server", version: "1.0.0" },
  { capabilities: { tools: {} } }
);

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: "shopify_funnel",
      description:
        "Shopifyのページファネル分析。訪問者→カート追加→チェックアウト到達→購入完了の各ステップの数値と遷移率を取得し、ボトルネックを特定します。ランディングページ別のコンバージョン率も確認できます。",
      inputSchema: {
        type: "object",
        properties: {
          days: {
            type: "number",
            description: "過去何日分を分析するか（デフォルト: 30）",
          },
          groupBy: {
            type: "string",
            enum: ["day", "week", "month", "landing_page", "referrer", "utm_source"],
            description: "グルーピング軸（デフォルト: day）",
          },
        },
      },
    },
    {
      name: "shopify_traffic_by_page",
      description:
        "Shopifyのランディングページ別トラフィック分析。どのページから入ってきたユーザーがコンバージョンしやすいかを把握できます。",
      inputSchema: {
        type: "object",
        properties: {
          days: { type: "number", description: "過去何日分（デフォルト: 30）" },
          limit: { type: "number", description: "取得するページ数（デフォルト: 20）" },
        },
      },
    },
    {
      name: "shopify_traffic_sources",
      description:
        "Shopifyの流入元（リファラー/UTM）別のセッション数・コンバージョン率を取得します。どの集客チャネルが効いているかを把握できます。",
      inputSchema: {
        type: "object",
        properties: {
          days: { type: "number", description: "過去何日分（デフォルト: 30）" },
          sourceType: {
            type: "string",
            enum: ["referrer", "utm_source", "utm_medium", "utm_campaign"],
            description: "集計する流入元のタイプ（デフォルト: referrer）",
          },
          limit: { type: "number", description: "取得する行数（デフォルト: 20）" },
        },
      },
    },
    {
      name: "shopify_product_performance",
      description:
        "Shopifyの商品別パフォーマンス。売上・注文数・平均単価を商品別に取得します。",
      inputSchema: {
        type: "object",
        properties: {
          days: { type: "number", description: "過去何日分（デフォルト: 30）" },
          limit: { type: "number", description: "取得する商品数（デフォルト: 20）" },
          orderBy: {
            type: "string",
            enum: ["net_sales", "orders", "units_sold"],
            description: "並べ替え基準（デフォルト: net_sales）",
          },
        },
      },
    },
    {
      name: "shopify_orders_summary",
      description:
        "Shopifyの注文サマリー。日別の注文数・売上・平均注文単価・割引額を取得します。",
      inputSchema: {
        type: "object",
        properties: {
          days: { type: "number", description: "過去何日分（デフォルト: 30）" },
          groupBy: {
            type: "string",
            enum: ["day", "week", "month"],
            description: "グルーピング軸（デフォルト: day）",
          },
        },
      },
    },
    {
      name: "shopify_custom_query",
      description:
        "カスタムShopifyQLクエリを実行します。sessionsデータセット（訪問者・ファネル・流入元）、ordersデータセット（注文・売上）、productsデータセット（商品パフォーマンス）に対して自由にクエリを書けます。",
      inputSchema: {
        type: "object",
        properties: {
          query: {
            type: "string",
            description:
              "ShopifyQLクエリ文字列。例: FROM sessions SHOW online_store_visitors, conversion_rate GROUP BY day SINCE startOfDay(-7d) UNTIL today ORDER BY day ASC",
          },
        },
        required: ["query"],
      },
    },
  ],
}));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  const { name, arguments: args } = request.params;

  if (!SHOPIFY_STORE || !SHOPIFY_ACCESS_TOKEN) {
    return {
      content: [
        {
          type: "text",
          text: "エラー: SHOPIFY_STORE または SHOPIFY_ACCESS_TOKEN 環境変数が設定されていません。Shopify管理画面でカスタムアプリを作成し、アクセストークンを設定してください。",
        },
      ],
    };
  }

  try {
    switch (name) {
      case "shopify_funnel": {
        const days = args?.days || 30;
        const groupBy = args?.groupBy || "day";
        const query = `
          FROM sessions
          SHOW online_store_visitors, sessions, sessions_with_cart_additions,
               sessions_that_reached_checkout, sessions_that_completed_checkout,
               conversion_rate
          GROUP BY ${groupBy}
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY ${groupBy} ASC
        `;
        const response = await runShopifyQL(query);
        let result = `## 🛒 Shopifyファネル分析（過去${days}日・${groupBy}別）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_traffic_by_page": {
        const days = args?.days || 30;
        const limit = args?.limit || 20;
        const query = `
          FROM sessions
          SHOW online_store_visitors, sessions, sessions_with_cart_additions,
               sessions_that_reached_checkout, sessions_that_completed_checkout,
               conversion_rate, pageviews
          GROUP BY landing_page_path
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY sessions DESC
          LIMIT ${limit}
        `;
        const response = await runShopifyQL(query);
        let result = `## 🚪 ランディングページ別トラフィック（過去${days}日）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_traffic_sources": {
        const days = args?.days || 30;
        const sourceType = args?.sourceType || "referrer";
        const limit = args?.limit || 20;
        const dimMap = {
          referrer: "referrer_source",
          utm_source: "utm_source",
          utm_medium: "utm_medium",
          utm_campaign: "utm_campaign",
        };
        const dim = dimMap[sourceType] || "referrer_source";
        const query = `
          FROM sessions
          SHOW online_store_visitors, sessions, sessions_with_cart_additions,
               sessions_that_completed_checkout, conversion_rate
          GROUP BY ${dim}
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY sessions DESC
          LIMIT ${limit}
        `;
        const response = await runShopifyQL(query);
        let result = `## 📊 流入元別分析（過去${days}日・${sourceType}別）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_product_performance": {
        const days = args?.days || 30;
        const limit = args?.limit || 20;
        const orderBy = args?.orderBy || "net_sales";
        const query = `
          FROM products
          SHOW net_sales, orders, units_sold, average_order_value
          GROUP BY product_title
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY ${orderBy} DESC
          LIMIT ${limit}
        `;
        const response = await runShopifyQL(query);
        let result = `## 📦 商品別パフォーマンス（過去${days}日）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_orders_summary": {
        const days = args?.days || 30;
        const groupBy = args?.groupBy || "day";
        const query = `
          FROM orders
          SHOW gross_sales, net_sales, orders, average_order_value,
               discounts, taxes, shipping
          GROUP BY ${groupBy}
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY ${groupBy} ASC
        `;
        const response = await runShopifyQL(query);
        let result = `## 💰 注文サマリー（過去${days}日・${groupBy}別）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_custom_query": {
        if (!args?.query) {
          return {
            content: [{ type: "text", text: "エラー: ShopifyQLクエリを指定してください。" }],
          };
        }
        const response = await runShopifyQL(args.query);
        let result = `## カスタムクエリ結果\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      default:
        return {
          content: [{ type: "text", text: `不明なツール: ${name}` }],
        };
    }
  } catch (error) {
    return {
      content: [
        {
          type: "text",
          text: `Shopify APIエラー: ${error.message}`,
        },
      ],
    };
  }
});

async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
}

main().catch(console.error);

