import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";

const SHOPIFY_STORE = process.env.SHOPIFY_STORE; // e.g. "your-store.myshopify.com"
const SHOPIFY_ACCESS_TOKEN = process.env.SHOPIFY_ACCESS_TOKEN;
const API_VERSION = "2025-01";

async function shopifyGraphQL(query, variables = {}) {
  const url = `https://${SHOPIFY_STORE}/admin/api/${API_VERSION}/graphql.json`;
  const res = await fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-Shopify-Access-Token": SHOPIFY_ACCESS_TOKEN,
    },
    body: JSON.stringify({ query, variables }),
  });

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Shopify API Error (${res.status}): ${text}`);
  }

  return res.json();
}

async function runShopifyQL(shopifyqlQuery) {
  const gql = `
    query ($query: String!) {
      shopifyqlQuery(query: $query) {
        __typename
        ... on TableResponse {
          tableData {
            unformattedData
            rowData
            columns {
              name
              dataType
              displayName
            }
          }
        }
        ... on PolarisVizResponse {
          data {
            key
            data {
              key
              value
            }
          }
        }
        parseErrors {
          code
          message
          range {
            start { line character }
            end { line character }
          }
        }
      }
    }
  `;

  const result = await shopifyGraphQL(gql, { query: shopifyqlQuery });

  if (result.errors) {
    throw new Error(`GraphQL errors: ${JSON.stringify(result.errors)}`);
  }

  const response = result.data.shopifyqlQuery;

  if (response.parseErrors && response.parseErrors.length > 0) {
    throw new Error(`ShopifyQL parse errors: ${JSON.stringify(response.parseErrors)}`);
  }

  return response;
}

function formatTableResponse(response) {
  if (response.__typename === "TableResponse" && response.tableData) {
    const { columns, rowData } = response.tableData;
    const headers = columns.map((c) => c.displayName || c.name);

    let result = `| ${headers.join(" | ")} |\n`;
    result += `| ${headers.map(() => "---").join(" | ")} |\n`;

    for (const row of rowData) {
      result += `| ${row.join(" | ")} |\n`;
    }

    result += `\n合計行数: ${rowData.length}`;
    return result;
  }

  if (response.__typename === "PolarisVizResponse" && response.data) {
    let result = "";
    for (const series of response.data) {
      result += `### ${series.key}\n`;
      for (const point of series.data) {
        result += `- ${point.key}: ${point.value}\n`;
      }
      result += "\n";
    }
    return result;
  }

  return "データがありません。";
}

const server = new Server(
