      case "shopify_funnel": {
        const days = args?.days || 30;
        const groupBy = args?.groupBy || "day";
        const query = `
          FROM sessions
          SHOW online_store_visitors, sessions, sessions_with_cart_additions,
               sessions_that_reached_checkout, sessions_that_completed_checkout,
               conversion_rate
          GROUP BY ${groupBy}
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY ${groupBy} ASC
        `;
        const response = await runShopifyQL(query);
        let result = `## 🛒 Shopifyファネル分析（過去${days}日・${groupBy}別）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_traffic_by_page": {
        const days = args?.days || 30;
        const limit = args?.limit || 20;
        const query = `
          FROM sessions
          SHOW online_store_visitors, sessions, sessions_with_cart_additions,
               sessions_that_reached_checkout, sessions_that_completed_checkout,
               conversion_rate, pageviews
          GROUP BY landing_page_path
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY sessions DESC
          LIMIT ${limit}
        `;
        const response = await runShopifyQL(query);
        let result = `## 🚪 ランディングページ別トラフィック（過去${days}日）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_traffic_sources": {
        const days = args?.days || 30;
        const sourceType = args?.sourceType || "referrer";
        const limit = args?.limit || 20;
        const dimMap = {
          referrer: "referrer_source",
          utm_source: "utm_source",
          utm_medium: "utm_medium",
          utm_campaign: "utm_campaign",
        };
        const dim = dimMap[sourceType] || "referrer_source";
        const query = `
          FROM sessions
          SHOW online_store_visitors, sessions, sessions_with_cart_additions,
               sessions_that_completed_checkout, conversion_rate
          GROUP BY ${dim}
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY sessions DESC
          LIMIT ${limit}
        `;
        const response = await runShopifyQL(query);
        let result = `## 📊 流入元別分析（過去${days}日・${sourceType}別）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_product_performance": {
        const days = args?.days || 30;
        const limit = args?.limit || 20;
        const orderBy = args?.orderBy || "net_sales";
        const query = `
          FROM products
          SHOW net_sales, orders, units_sold, average_order_value
          GROUP BY product_title
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY ${orderBy} DESC
          LIMIT ${limit}
        `;
        const response = await runShopifyQL(query);
        let result = `## 📦 商品別パフォーマンス（過去${days}日）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_orders_summary": {
        const days = args?.days || 30;
        const groupBy = args?.groupBy || "day";
        const query = `
          FROM orders
          SHOW gross_sales, net_sales, orders, average_order_value,
               discounts, taxes, shipping
          GROUP BY ${groupBy}
          SINCE startOfDay(-${days}d) UNTIL today
          ORDER BY ${groupBy} ASC
        `;
        const response = await runShopifyQL(query);
        let result = `## 💰 注文サマリー（過去${days}日・${groupBy}別）\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      case "shopify_custom_query": {
        if (!args?.query) {
          return {
            content: [{ type: "text", text: "エラー: ShopifyQLクエリを指定してください。" }],
          };
        }
        const response = await runShopifyQL(args.query);
        let result = `## カスタムクエリ結果\n\n`;
        result += formatTableResponse(response);
        return { content: [{ type: "text", text: result }] };
      }

      default:
        return {
          content: [{ type: "text", text: `不明なツール: ${name}` }],
        };
    }
  } catch (error) {
    return {
      content: [
        {
          type: "text",
          text: `Shopify APIエラー: ${error.message}`,
        },
      ],
    };
  }
});

